VALUES
  ('dietitian-moex-01013', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '鐮刀型貧血（sickle-cellanemia）是一種遺傳基因缺陷的疾病，主要是因為那一種蛋白質異常所導 致？', '["白蛋白（albumin）", "血紅素（hemoglobin）", "內在因子（intrinsicfactor）", "C-反應型蛋白（C-reactiveprotein）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01014', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列關於各類胺基酸在腎臟代謝的敘述，何者錯誤？', '["麩醯胺酸（glutamine）在腎臟代謝後，可參與酸鹼平衡的作用", "精胺酸（arginine）和甘胺酸（glycine）在腎臟中可以生成胍基乙酸酯（guanidinoacetate），進一 步於其他組織參與肌酸（creatine）的生合成", "多數胺基酸，例如精胺酸（arginine）、組胺酸（histidine）和絲胺酸（serine）等，可在腎臟中生成", "穀胱甘肽（glutathione）主要是在腎臟中形成"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01015', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列關於膠原蛋白（collagen）的敘述，何者錯誤？', '["膠原蛋白是脊椎動物體內含量豐富的蛋白質之一", "組合成膠原蛋白的重要胺基酸，包含甘胺酸（glycine）、脯胺酸（proline）以及離胺酸（lysine）等", "維生素C可協助將脯胺酸（proline）從膠原蛋白的殘基中解離", "原膠原蛋白（tropocollagen）由三條多胜肽（polypeptide）纏繞而成，是膠原蛋白的基本構造單位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01016', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列關於不同RNA（ribonucleicacid）的敘述，何者正確？', '["訊息RNA（messengerRNA,mRNA）本身可攜帶胺基酸合成蛋白質", "人體內的核糖體（ribosome）中，核糖體RNA（ribosomalRNA,rRNA）大小為30S", "小核RNA（smallnuclearRNA,snRNA）參與轉運RNA（transferRNA,tRNA）製造過程", "轉運RNA（transferRNA,tRNA）相較於其他種類RNA，含有最多之非典型鹼基"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01017', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列關於人類DNA的敘述，何者正確？', '["為一環狀雙股（circulardouble-helical）結構", "約有1%之細胞中DNA位於粒線體（mitochondria）", "不到10%基因組（genome）具有重複序列（repetitivesequences）", "DNA之蛋白質譯碼（coding）區域不會出現外顯子（exon）介入序列（interveningsequences）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01018', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列關於嘌呤核苷（purinenucleosides）分解的敘述，何者正確？', '["分解之最終產物為尿素（urea）", "分解過程包括去胺作用（deamination）", "分解過程最後一步驟為還原作用（reduction）", "若嘌呤核苷磷酸酶（purinenucleosidephoshorylase）缺乏，會導致貧血"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01019', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者會導致嘧啶二聚體（pyrimidinedimer）結構形式之DNA損傷？', '["烷化作用（alkylation）", "去胺作用（deamination）", "去嘌呤作用（depurination）", "甲基化作用（methylation）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01020', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '葡萄糖經六碳醣激酶（hexokinase）作用生成葡萄糖-6-磷酸，其逆反應由葡萄糖-6-磷酸酶 （phosphatase）催化移除磷酸根。關於這兩個酵素的敘述，下列何者錯誤？', '["反應需要磷酸根的轉移，兩個酵素都屬於IUB系統的轉移酶（transferase）", "兩個酵素所催化的反應之ΔG都是負值", "激酶反應需要ATP，而磷酸酶反應不需要ATP", "兩個反應都在細胞質中進行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01021', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '所謂呼吸鏈偶合氧化磷酸化（coupling oxidative phosphorylation），意指以下那兩個反應伴隨（偶 合）發生：', '["NADH+1/2O +H+ → H O+NAD+", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01022', 'dietitian', 'dietitian-moex-111-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '2', '["Pyruvate+NADH+H+ → lactate + NAD+", "ADP+P +H+ → ATP + H O i 2", "Creatine phosphate + ADP → ATP + creatine", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "fe0d648474ae", "answer_pdf_sha1": "f65841dc3617", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
